1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return an empty set when there are no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single living cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill a living cell with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep alive a living cell with two live neighbors", () => {
15	    expect(nextGeneration([[0, 0], [1, 1], [2, 2]])).toEqual([[1, 1]]);
16	  });
17	  it("should keep alive a living cell with three live neighbors", () => {
18	    expect(nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]).sort()).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]].sort());
19	  });
20	  it("should kill a living cell with four live neighbors (overpopulation)", () => {
21	    expect(nextGeneration([[0, 0], [-1, 0], [1, 0], [0, -1], [0, 1]])).not.toContainEqual([0, 0]);
22	  });
23	  it("should bring a dead cell with exactly three live neighbors to life (reproduction)", () => {
24	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]]).sort()).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]].sort());
25	  });
26	  it.todo("should handle living cells with negative coordinates");
27	  it.todo("should produce the correct next generation for a blinker pattern (oscillator)");
28	});
29

1	type Cell = [number, number];
2	
3	const areNeighbors = ([x1, y1]: Cell, [x2, y2]: Cell): boolean => {
4	  const dx = x2 - x1;
5	  const dy = y2 - y1;
6	  return (dx !== 0 || dy !== 0) && Math.abs(dx) <= 1 && Math.abs(dy) <= 1;
7	};
8	
9	const countLivingNeighbors = (cell: Cell, livingCells: Cell[]): number =>
10	  livingCells.filter((other) => areNeighbors(cell, other)).length;
11	
12	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
13	
14	const deadNeighborsOf = (livingCells: Cell[]): Cell[] => {
15	  const livingKeys = new Set(livingCells.map(cellKey));
16	  const deadCells = new Map<string, Cell>();
17	  for (const [x, y] of livingCells) {
18	    for (let dx = -1; dx <= 1; dx++) {
19	      for (let dy = -1; dy <= 1; dy++) {
20	        if (dx === 0 && dy === 0) continue;
21	        const candidate: Cell = [x + dx, y + dy];
22	        const key = cellKey(candidate);
23	        if (!livingKeys.has(key)) {
24	          deadCells.set(key, candidate);
25	        }
26	      }
27	    }
28	  }
29	  return [...deadCells.values()];
30	};
31	
32	export function nextGeneration(livingCells: Cell[]): Cell[] {
33	  const survivors = livingCells.filter((cell) => {
34	    const neighbors = countLivingNeighbors(cell, livingCells);
35	    return neighbors === 2 || neighbors === 3;
36	  });
37	
38	  const born = deadNeighborsOf(livingCells).filter(
39	    (cell) => countLivingNeighbors(cell, livingCells) === 3,
40	  );
41	
42	  return [...survivors, ...born];
43	}
